27	export const runScenario = (input: any): { results: unknown[] } => {
28	  const items: { type: string }[] = input.steps[0].items;
29	  const countsByType = new Map<string, number>();
30	  for (const item of items) {
31	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
32	  }
33	  let premium = PROCESSING_FEE;
34	  for (const [type, count] of countsByType) {
35	    premium += groupBase(type, count);
36	  }
37	  return { results: [{ premium: Math.ceil(premium) }] };
38	};
